code = """import json
import sqlite3
import os

# Connect to molecular database to get comprehensive BRCA data
brca_participants = []

# First, let's get all unique BRCA participants from mutation data
try:
    # Read the file directly
    for filename in os.listdir('.'):
        if 'query_db_56' in filename and filename.endswith('.json'):
            with open(filename, 'r') as f:
                data = json.load(f)
                brca_participants = [row['Participant_ID'] for row in data]
                break
    
    print(f"Found {len(brca_participants)} BRCA participants from molecular data")
    
    # Get clinical data
    clinical_file = None
    for filename in os.listdir('.'):
        if 'query_db_46' in filename and filename.endswith('.json'):
            clinical_file = filename
            break
    
    if clinical_file:
        with open(clinical_file, 'r') as f:
            clinical_data = json.load(f)
        print(f"Loaded {len(clinical_data)} clinical records")
    else:
        print("No clinical file found")
        clinical_data = []
    
    # Extract BRCA patients from clinical data and match histological types
    brca_clinical = {}
    
    for record in clinical_data:
        desc = record.get("Patient_description", "")
        hist_type = record.get("histological_type", "")
        
        # Look for BRCA patterns
        import re
        match = re.search(r'(TCGA-[A-Z0-9]+-[0-9]+)', desc)
        if match:
            barcode = match.group(1)
            participant_id = '-'.join(barcode.split('-')[:3])
            
            # Check if this is a BRCA participant (tumor code patterns)
            tumor_code = barcode.split('-')[1] if len(barcode.split('-')) > 1 else ""
            if tumor_code in ['A1', 'A2', 'A7', 'A8', 'AR', 'AC', 'AE', 'AN', 'AQ', 'A6', 'AO', 'AP']:
                if participant_id in brca_participants or len(brca_participants) == 0:
                    brca_clinical[participant_id] = {
                        'histological_type': hist_type,
                        'barcode': participant_id,
                        'description': desc[:100]
                    }
    
    print(f"Matched {len(brca_clinical)} BRCA participants with clinical data")
    
    # Save results
    result = {
        'brca_participants': brca_participants[:10],  # Sample
        'clinical_matches': len(brca_clinical),
        'sample_clinical': list(brca_clinical.values())[:5]
    }
    
    print(json.dumps(result, indent=2))
    
except Exception as e:
    print(f"Error: {e}")"""

